canonical_solution:
pub fn swap_elements<T>(slice: &mut [T], i: usize, j: usize) {
    assert!(i < slice.len() && j < slice.len());
    if i == j { return; }
    let ptr = slice.as_mut_ptr();
    unsafe {
        std::ptr::swap(ptr.add(i), ptr.add(j));
    }
}

